# Generate Lean proof for amc12a_2009_p25
# Strategy: compute a(1)..a(26), show a(25)=a(1), a(26)=a(2), period 24, 2009 mod 24 = 17, a(17)=0

from fractions import Fraction

# Symbolic computation with √3
# Represent values as (p + q√3) / (r + s√3) but simplified to (a + b√3) form
# where a, b are rationals.
# (a + b√3) * (c + d√3) = (ac + 3bd) + (ad + bc)√3
# (a + b√3) / (c + d√3) = ((a + b√3)(c - d√3)) / (c² - 3d²)
#   = (ac - 3bd + (bc - ad)√3) / (c² - 3d²)

class Sqrt3:
    """Represents a + b*sqrt(3) where a, b are Fraction"""
    def __init__(self, a, b=0):
        self.a = Fraction(a)
        self.b = Fraction(b)

    def __add__(self, other):
        return Sqrt3(self.a + other.a, self.b + other.b)

    def __sub__(self, other):
        return Sqrt3(self.a - other.a, self.b - other.b)

    def __mul__(self, other):
        return Sqrt3(self.a * other.a + 3 * self.b * other.b,
                     self.a * other.b + self.b * other.a)

    def __truediv__(self, other):
        denom = other.a * other.a - 3 * other.b * other.b
        assert denom != 0, f"Division by zero: {other}"
        conj = Sqrt3(other.a, -other.b)
        num = self * conj
        return Sqrt3(num.a / denom, num.b / denom)

    def __neg__(self):
        return Sqrt3(-self.a, -self.b)

    def __eq__(self, other):
        return self.a == other.a and self.b == other.b

    def __repr__(self):
        if self.b == 0:
            return str(self.a)
        elif self.a == 0:
            if self.b == 1:
                return "s"
            elif self.b == -1:
                return "-s"
            return f"{self.b}*s"
        sign = "+" if self.b > 0 else "-"
        babs = abs(self.b)
        bstr = f"{babs}*" if babs != 1 else ""
        return f"{self.a} {sign} {bstr}s"

    def to_lean(self):
        """Convert to Lean expression using s for √3"""
        if self.b == 0:
            return self._frac_to_lean(self.a)
        elif self.a == 0:
            b_lean = self._frac_to_lean(self.b)
            if b_lean == "1":
                return "s"
            elif b_lean == "-1" or b_lean == "-(1)":
                return "(-s)"
            return f"({b_lean} * s)"
        a_lean = self._frac_to_lean(self.a)
        b_lean = self._frac_to_lean(self.b)
        if b_lean == "1":
            return f"({a_lean} + s)"
        elif b_lean == "-1" or b_lean == "-(1)":
            return f"({a_lean} - s)"
        return f"({a_lean} + {b_lean} * s)"

    def _frac_to_lean(self, f):
        f = Fraction(f)
        if f.denominator == 1:
            return str(f.numerator)
        return f"({f.numerator} / {f.denominator})"

# Compute sequence
ONE = Sqrt3(1)
ZERO = Sqrt3(0)
S = Sqrt3(0, 1)  # √3

